Description.TranslatedText:
set to 'Screen Failure' if ACTARMCD='SCRNFAIL',
else 'Not Treated' if ACTARMCD='NOTTRT',
else 'YJ001 240mg' if ACTARMCD='S1',
else 'YJ001 480mg' if ACTARMCD='S2',
else 'YJ001 720mg' if ACTARMCD='S3',
else 'YJ001 960mg' if ACTARMCD='S4',
else 'Placebo' if ACTARMCD='P'

set to 'SCRNFAIL' if RAND.RANDYN_DESC="No"
else set to 'NOTTRT' if not missing of RAND.RANDNUM and missing(RFSTDTC),
else merge from external file: 盲底YJ整理-20210106发圣方.xlsx

set to 'Screen Failure' if ARMCD='SCRNFAIL',
else 'YJ001 240mg' if ARMCD='S1',
else 'YJ001 480mg' if ARMCD='S2',
else 'YJ001 720mg' if ARMCD='S3',
else 'YJ001 960mg' if ARMCD='S4',
else 'Placebo' if ARMCD='P'

For ICF dataset: set to "PROTOCOL MILESTONE";
For rand dataset: if RANDYN_DESC="Yes" then set to "PROTOCOL MILESTONE", else set to "DISPOSITION EVENT"
For ds dataset: set to "DISPOSITION EVENT"

For ICF dataset: set to ICFDAT, displayed in ISO 8601 format;
For DSDECOD="SCREEN FAILURE", set to DM.RFPENDTC;
For DSDECOD="ENTERED INTO TRIAL", set to suppdm.qval where qnam="RANDDTC";

For ICF dataset: set to "INFORMED CONSENT OBTAINED";
For rand dataset: if RANDYN_DESC="Yes" then set to "ENTERD INTO TRIAL", else set to RANDESC
For ds dataset: if DSCOMP_DESC="Yes" then set to "COMPLETED", else set to DSREA_DESC

set to "Hematology" when from LBBR/LBBM/LBBRP;
set to "Serum Biochemistry" when from LBBC/LBCM/LBBCP;
set to "Urinalysis" when from LBUR/LBUM/LBURP;
set to "Coagulation" when from LBCT/LBCTP;
set to "Pregnancy Test" when from BHCG/UHCG;
set to "Breathalyzer Test" when from AC;
set to "Urine Drugs of Abuse Test" when from DR;
UP.uptest, set to "Serum Biochemistry" when UP.uptest="Serum biochemistry";

LBBR/LBBM/LBBRP/LBBC/LBCM/LBBCP/LBUR/LBUM/LBURP/ LBCT/LBCTP.lbornrhi, 
if up.upcheck in "Amylase","Bacteria","Creatine kinase isoenzymes","Leukocytes count","Leukocytes count (manual)","Red blood cell count","Red blood cell count (manual)",
 "Total bile acids","Uric acid","α-hydroxybutyrate dehydrogenase" then set to num part of up.upscope after "-" or "~";

LBBR/LBBM/LBBRP/LBBC/LBCM/LBBCP/LBUR/LBUM/LBURP/ LBCT/LBCTP.lbornrlo, 
if up.upcheck in "Amylase","Bacteria","Creatine kinase isoenzymes","Leukocytes count","Leukocytes count (manual)","Red blood cell count","Red blood cell count (manual)",
 "Total bile acids","Uric acid","α-hydroxybutyrate dehydrogenase" then set to num part of up.upscope before "-" or "~";

LBBR/LBBM/LBBRP/LBBC/LBCM/LBBCP/LBUR/LBUM/LBURP/ LBCT/LBCTP.lborres, BHCG.BGRES, UHCG.UGRES_DESC, AC.BGRES, DR.DRSIG_DESC, 
if up.upcheck in "Amylase","Bacteria","Creatine kinase isoenzymes","Leukocytes count","Leukocytes count (manual)","Red blood cell count","Red blood cell count (manual)",
 "Total bile acids","Uric acid","α-hydroxybutyrate dehydrogenase" then set to num part of up.uporres;
if up.upcheck in "Hidden blood in urine","Leukocyte esterase","Others","Urine leukocyte esterase" then set to up.uporres;

LBBR/LBBM/LBBRP/LBBC/LBCM/LBBCP/LBUR/LBUM/LBURP/ LBCT/LBCTP.lbesu, BHCG.BGRESU, AC.BGRESU, 
if up.upcheck in "Amylase","Bacteria","Creatine kinase isoenzymes","Leukocytes count","Leukocytes count (manual)","Red blood cell count","Red blood cell count (manual)",
 "Total bile acids","Uric acid","α-hydroxybutyrate dehydrogenase" then set to unit part of up.uporres;

set to "SERUM" when from BHCG;
set to "URINE" when from LBUR/LBUM/LBURP/UHCG;
set to "URINE" when up.uptest in "Urinalysis","Urinary sediment","Urine";

set to "umol/L" when lb.lborresu="μmol/L";
set to "sec" when lb.lborresu="s";
set to "mIU/mL" when lb.lborresu="mIU/ml";
set to "mg/100mL" when lb.lborresu="mg/100ml";
set to "umol/L" when lb.lborresu="umol/l";
set to "U/L" when lb.lborresu="u/l";
set to "/mL" when lb.lborresu="/ml";
set to "p/uL" when lb.lborresu="p/μl";

set to "SKI" when pe.petest/pep.petest="Skin";
set to "MUS" when pe.petest/pep.petest="Mucosa";
set to "LYM" when pe.petest/pep.petest="Lymph nodes";
set to "HEAD" when pe.petest/pep.petest="Head";
set to "NECK" when pe.petest/pep.petest="Neck";
set to "CHE" when pe.petest/pep.petest="Chest";
set to "ABD" when pe.petest/pep.petest="Abdomen";
set to "SPI" when pe.petest/pep.petest="Spine/limbs";

set to 37.7 when VS.VSTESTCD="TEMP";
set to 20 when VS.VSTESTCD="RESP";
set to 100 when VS.VSTESTCD="PULSE";
set to 140 when VS.VSTESTCD="SYSBP";
set to 90 when VS.VSTESTCD="DIABP";

set to 35.4 when VS.VSTESTCD="TEMP";
set to 12 when VS.VSTESTCD="RESP";
set to 50 when VS.VSTESTCD="PULSE";
set to 90 when VS.VSTESTCD="SYSBP";
set to 50 when VS.VSTESTCD="DIABP";

set to "C" when vs.vsorresu="°C";
set to "kg/m2" when vs.vsorresu="kg/㎡";
set to "beats/min" when vs.vsorresu="times/min" and vs.vstestcd="PULSE";
set to "breaths/min" when vs.vsorresu="times/min" and vs.vstestcd="RESP";

set to "Height" when VS.VSTESTCD="HEIGHT";
set to "Weight" when VS.VSTESTCD="WEIGHT";
set to "Body Mass Index" when VS.VSTESTCD="BMI";
set to "Temperature" when VS.VSTESTCD="TEMP";
set to "Respiratory Rate" when VS.VSTESTCD="RESP";
set to "Pulse Rate" when VS.VSTESTCD="PULSE";
set to "Systolic Blood Pressure" when VS.VSTESTCD="SYSBP";
set to "Diastolic Blood Pressure" when VS.VSTESTCD="DIABP";

set to "HEIGHT" when DM.height;
set to "WEIGHT" when DM.weight;
set to "BMI" when DM.index;
set to "TEMP" when VS/VSF1-VSF7/VSP.vstemp;
set to "RESP" when VS/VSF1-VSF7/VSP.vsbrea;
set to "PULSE" when VS/VSF1-VSF7/VSP.vspulse;
set to "SYSBP" when VS/VSF1-VSF7/VSP.vssbp;
set to "DIABP" when VS/VSF1-VSF7/VSP.vsdbp;

set to "6h" when from VSF1;
set to "12h" when from VSF2;
set to "24h" when from VSF3;
set to "48h" when from VSF4;
set to "72h" when from VSF5;
set to "120h" when from VSF6;
set to "168h" when from VSF7;

set to 6 when from VSF1;
set to 12 when from VSF2;
set to 24 when from VSF3;
set to 48 when from VSF4;
set to 72 when from VSF5;
set to 120 when from VSF6;
set to 168 when from VSF7;
